import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Limiting the size of buffer to avoid buffer overflow
        byte[] buffer = new byte[10];
        int length = Math.min(userInput.length(), buffer.length);
        for (int i = 0; i < length; i++) {
            buffer[i] = (byte) userInput.charAt(i);
        }

        System.out.println("Buffer filled with user input: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
